import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API_URL = process.env.REACT_APP_API_URL || '';

function SMSVerify({ phone, onVerified }) {
  const [code, setCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [countdown, setCountdown] = useState(0);
  const [codeSent, setCodeSent] = useState(false);
  const [demoCode, setDemoCode] = useState(null);

  const token = localStorage.getItem('token');

  useEffect(() => {
    if (countdown > 0) {
      const timer = setTimeout(() => setCountdown(countdown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [countdown]);

  const sendCode = async () => {
    setLoading(true);
    setMessage('');
    try {
      const res = await axios.post(`${API_URL}/api/sms/send`, 
        { phone },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setCodeSent(true);
      setCountdown(60);
      
      if (res.data.demoCode) {
        setDemoCode(res.data.demoCode);
        setMessage(`Demo mode: Your code is ${res.data.demoCode}`);
      } else {
        setMessage('Code sent! Check your phone.');
      }
    } catch (err) {
      setMessage(err.response?.data?.error || 'Failed to send code');
    }
    setLoading(false);
  };

  const verifyCode = async () => {
    if (code.length !== 6) {
      setMessage('Please enter the 6-digit code');
      return;
    }

    setLoading(true);
    setMessage('');
    try {
      await axios.post(`${API_URL}/api/sms/verify`,
        { phone, code },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setMessage('✅ Phone verified successfully!');
      setTimeout(() => onVerified?.(), 1500);
    } catch (err) {
      setMessage(err.response?.data?.error || 'Invalid code');
    }
    setLoading(false);
  };

  return (
    <div className="bg-white rounded-2xl shadow-lg p-8 max-w-md mx-auto">
      <div className="text-center mb-6">
        <div className="text-5xl mb-4">📱</div>
        <h3 className="text-2xl font-bold text-gray-900">Verify Phone Number</h3>
      </div>
      
      <div className="bg-gray-50 rounded-xl p-4 mb-6 text-center">
        <p className="text-gray-600">Sending code to:</p>
        <p className="text-xl font-semibold text-gray-900">{phone}</p>
      </div>

      {message && (
        <div className={`p-4 rounded-xl mb-6 text-center ${message.includes('success') || message.includes('Demo') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
          {message}
        </div>
      )}

      {!codeSent ? (
        <button
          onClick={sendCode}
          disabled={loading}
          className="w-full bg-blue-600 text-white py-4 rounded-xl text-lg font-semibold hover:bg-blue-700 disabled:bg-gray-400 transition-all"
        >
          {loading ? 'Sending...' : 'Send Verification Code'}
        </button>
      ) : (
        <div className="space-y-4">
          <div className="text-center">
            <label className="block text-sm font-medium text-gray-700 mb-2">Enter 6-digit code</label>
            <input
              type="text"
              maxLength="6"
              value={code}
              onChange={(e) => setCode(e.target.value.replace(/\D/g, ''))}
              placeholder="______"
              className="w-full p-4 border-2 border-gray-200 rounded-xl text-center text-3xl tracking-[0.5em] font-mono focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition-all"
            />
          </div>

          <button
            onClick={verifyCode}
            disabled={loading || code.length !== 6}
            className="w-full bg-green-600 text-white py-4 rounded-xl text-lg font-semibold hover:bg-green-700 disabled:bg-gray-400 transition-all"
          >
            {loading ? 'Verifying...' : 'Verify Code'}
          </button>

          <button
            onClick={sendCode}
            disabled={countdown > 0 || loading}
            className="w-full text-blue-600 py-3 font-medium disabled:text-gray-400 transition-colors"
          >
            {countdown > 0 ? `Resend in ${countdown}s` : 'Resend Code'}
          </button>
        </div>
      )}
    </div>
  );
}

export default SMSVerify;

