import React, { useState, useEffect } from 'react';
import axios from 'axios';
import CameraCapture from './CameraCapture';

const API_URL = process.env.REACT_APP_API_URL || '';

const SHOTS = [
  { key: 'idFront', label: 'Front of your ID', icon: '🪪', hint: 'Lay your ID on a flat surface in good light' },
  { key: 'idBack', label: 'Back of your ID', icon: '🪪', hint: 'Flip it over — make sure text is readable' },
  { key: 'selfie', label: 'Selfie with your ID', icon: '🤳', hint: 'Hold your ID next to your face' },
];

function Verification({ embedded, onStatusChange }) {
  const [files, setFiles] = useState({});       // key -> File
  const [previews, setPreviews] = useState({}); // key -> url
  const [shotIdx, setShotIdx] = useState(0);
  const [idNumber, setIdNumber] = useState('');
  const [status, setStatus] = useState(null);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');

  const token = localStorage.getItem('token');

  useEffect(() => {
    checkStatus();
  }, []);

  const checkStatus = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/verification/status`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setStatus(res.data.status);
    } catch (err) {
      console.error('Status check failed:', err);
    }
  };

  const handleCapture = (captured, key) => {
    const file = captured[0];
    if (!file) return;
    setFiles(prev => ({ ...prev, [key]: file }));
    setPreviews(prev => ({ ...prev, [key]: URL.createObjectURL(file) }));
  };

  const allCaptured = SHOTS.every(s => files[s.key]);

  const handleSubmit = async () => {
    if (!allCaptured) {
      setMessage('Please take all three photos');
      return;
    }
    setLoading(true);
    const formData = new FormData();
    formData.append('idFront', files.idFront);
    formData.append('idBack', files.idBack);
    formData.append('selfie', files.selfie);
    if (idNumber) formData.append('idNumber', idNumber);

    try {
      await axios.post(`${API_URL}/api/verification/upload`, formData, {
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'multipart/form-data'
        }
      });
      setMessage('✅ Documents uploaded! Pending review.');
      setStatus('pending');
      if (onStatusChange) setTimeout(onStatusChange, 1200);
    } catch (err) {
      setMessage(err.response?.data?.error || 'Upload failed');
    }
    setLoading(false);
  };

  const wrap = (children) => embedded
    ? <div>{children}</div>
    : (
      <div className="max-w-lg mx-auto p-4">
        <div className="bg-white rounded-2xl shadow-lg p-5 sm:p-8">{children}</div>
      </div>
    );

  if (status === 'verified') {
    return wrap(
      <div className="text-center py-6 animate-fadeIn">
        <div className="text-5xl mb-4">✅</div>
        <h2 className="text-2xl font-bold text-green-600 mb-2">Verified!</h2>
        <p className="text-gray-600 mb-4">Your identity has been verified.</p>
        <div className="inline-flex items-center px-5 py-2.5 bg-green-100 text-green-800 rounded-full font-medium">
          <span className="mr-2">✓</span> Verified User
        </div>
      </div>
    );
  }

  if (status === 'pending') {
    return wrap(
      <div className="text-center py-6 animate-fadeIn">
        <div className="text-5xl mb-4">⏳</div>
        <h2 className="text-2xl font-bold text-yellow-600 mb-2">Under Review</h2>
        <p className="text-gray-600">Your documents are being reviewed.</p>
        <p className="text-gray-400 text-sm mt-1">This usually takes 24–48 hours.</p>
      </div>
    );
  }

  const shot = SHOTS[Math.min(shotIdx, SHOTS.length - 1)];
  const onReview = shotIdx >= SHOTS.length;

  return wrap(
    <div className="animate-fadeIn">
      {!embedded && (
        <div className="text-center mb-5">
          <div className="text-4xl mb-2">🪪</div>
          <h2 className="text-xl sm:text-2xl font-bold text-gray-900">Verify Your Identity</h2>
          <p className="text-gray-500 text-sm mt-1">3 quick photos — the biggest boost to your trust stars</p>
        </div>
      )}

      {/* Progress */}
      <div className="mb-5">
        <div className="h-2 bg-gray-100 rounded-full overflow-hidden">
          <div className="h-full bg-blue-600 rounded-full transition-all duration-500"
            style={{ width: `${(Math.min(shotIdx + 1, 4) / 4) * 100}%` }} />
        </div>
        <div className="flex justify-between text-xs text-gray-400 mt-1">
          <span className={shotIdx >= 0 ? 'text-blue-600 font-semibold' : ''}>Front</span>
          <span className={shotIdx >= 1 ? 'text-blue-600 font-semibold' : ''}>Back</span>
          <span className={shotIdx >= 2 ? 'text-blue-600 font-semibold' : ''}>Selfie</span>
          <span className={onReview ? 'text-blue-600 font-semibold' : ''}>Submit</span>
        </div>
      </div>

      {message && (
        <div className={`p-3 rounded-xl mb-4 text-center text-sm font-medium ${message.startsWith('✅') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
          {message}
        </div>
      )}

      {!onReview ? (
        /* ── One photo at a time ── */
        <div className="space-y-4">
          <div className="text-center">
            <div className="text-3xl mb-1">{shot.icon}</div>
            <h3 className="font-bold text-gray-900">{shot.label}</h3>
            <p className="text-gray-400 text-xs mt-1">{shot.hint}</p>
          </div>

          {previews[shot.key] ? (
            <img src={previews[shot.key]} alt={`${shot.label} preview`} className="w-full max-h-52 object-contain rounded-xl bg-gray-50" />
          ) : (
            <div className="bg-gray-50 h-40 rounded-xl flex items-center justify-center">
              <span className="text-gray-300 text-sm">No photo yet</span>
            </div>
          )}

          <CameraCapture
            onCapture={(f) => handleCapture(f, shot.key)}
            maxPhotos={1}
            label={files[shot.key] ? 'Retake Photo' : 'Take Photo'}
            disabled={false}
          />

          <div className="flex gap-3">
            {shotIdx > 0 && (
              <button onClick={() => setShotIdx(i => i - 1)}
                className="flex-1 bg-gray-100 text-gray-700 py-3 rounded-xl font-semibold hover:bg-gray-200 transition-all text-sm">
                ← Back
              </button>
            )}
            <button onClick={() => files[shot.key] && setShotIdx(i => i + 1)}
              disabled={!files[shot.key]}
              className="flex-[2] bg-blue-600 text-white py-3 rounded-xl font-semibold hover:bg-blue-700 disabled:bg-gray-300 transition-all text-sm">
              {shotIdx === SHOTS.length - 1 ? 'Review →' : 'Next →'}
            </button>
          </div>
        </div>
      ) : (
        /* ── Review & submit ── */
        <div className="space-y-4">
          <div className="grid grid-cols-3 gap-2">
            {SHOTS.map((s, i) => (
              <button key={s.key} onClick={() => setShotIdx(i)} className="relative">
                <img src={previews[s.key]} alt={s.label} className="w-full h-20 object-cover rounded-lg" />
                <span className="absolute bottom-1 left-1 right-1 text-[9px] font-bold text-white bg-black/50 rounded px-1 truncate">{s.label}</span>
              </button>
            ))}
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">ID Number <span className="text-gray-400 font-normal">(optional)</span></label>
            <input
              type="text"
              inputMode="numeric"
              value={idNumber}
              onChange={(e) => setIdNumber(e.target.value)}
              className="w-full p-3 border-2 border-gray-200 rounded-xl focus:border-blue-500 text-sm"
              placeholder="Your 13-digit SA ID number"
            />
          </div>

          <div className="flex gap-3">
            <button onClick={() => setShotIdx(0)}
              className="flex-1 bg-gray-100 text-gray-700 py-3 rounded-xl font-semibold hover:bg-gray-200 transition-all text-sm">
              ← Retake
            </button>
            <button onClick={handleSubmit} disabled={loading || !allCaptured}
              className="flex-[2] bg-blue-600 text-white py-3 rounded-xl font-semibold hover:bg-blue-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition-all text-sm">
              {loading ? 'Uploading...' : 'Submit for Verification'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default Verification;
